class EventEmitter {
  constructor() {
    this.events = {};
  }
  on(event, listener) {
    (this.events[event] = this.events[event] || []).push(listener);
  }
  emit(event, data) {
    (this.events[event] || []).forEach(listener => listener(data));
  }
}

const dataEvents = new EventEmitter();

dataEvents.on('userUpdate', (user) => {
  console.log('User updated:', user);
});

dataEvents.emit('userUpdate', { id: 'user1', name: 'Alice Smith' });

setTimeout(() => {
  // This error is asynchronous
  throw new Error('Async error inside setTimeout');
}, 1000);

// This will not catch the async error
try {
  setTimeout(() => {
    throw new Error('Async error inside setTimeout');
  }, 1000);
} catch (err) {
  console.log('Caught error:', err);
}

function asyncOperation() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      reject(new Error('Error inside promise'));
    }, 1000);
  });
}

asyncOperation()
  .catch(err => {
    console.log('Caught async error:', err.message);
  });

async function runAsync() {
  try {
    await asyncOperation();
  } catch(err) {
    console.log('Caught async error with await:', err.message);
  }
}

runAsync();

