  }
}

class Cat {
  meow() {
    console.log('Meow!');
  }
}

function speak(animal: Dog | Cat) {
  if (animal instanceof Dog) {
    animal.bark(); // TypeScript knows 'animal' is Dog
  } else {
    animal.meow(); // TypeScript knows 'animal' is Cat
  }
}

speak(new Dog());
speak(new Cat());

